namespace sv_bdb68489ddd34450ad0a10e995ee4521.Services;

public class Warehouse
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service that tracks the currently selected warehouse per circuit.
/// Components subscribe to <see cref="OnChange"/> and call
/// <c>InvokeAsync(StateHasChanged)</c> when notified.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<Warehouse> AvailableWarehouses =
    [
        new Warehouse { Id = "WH-A", Name = "Warehouse A" },
        new Warehouse { Id = "WH-B", Name = "Warehouse B" },
        new Warehouse { Id = "WH-C", Name = "Warehouse C" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;
    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_bdb68489ddd34450ad0a10e995ee4521.Services;

/// <summary>
/// Scoped service that polls for low-stock item counts and notifies all
/// subscribers when new data arrives. Polling is started/stopped explicitly
/// so it only runs while the dashboard is visible.
/// </summary>
public class InventoryAlertService : IAsyncDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();

    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int LowStockCount { get; private set; }

    /// <summary>
    /// Raised on the thread-pool when new alert data arrives.
    /// Subscribers MUST wrap StateHasChanged in InvokeAsync.
    /// </summary>
    public event Action? OnAlertDataChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += OnWarehouseChanged;
    }

    /// <summary>Simulates a database query.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Adds a subscriber and starts polling if this is the first one.
    /// Call <see cref="StopPolling"/> when the component disposes.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _ = PollLoopAsync(_cts.Token);
        }
    }

    /// <summary>
    /// Removes a subscriber and stops polling when the last one leaves.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _cts?.Cancel();
            _cts?.Dispose();
            _cts = null;
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        // Fetch immediately on start, then every 10 seconds.
        await FetchAndNotifyAsync();
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await FetchAndNotifyAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when polling is stopped.
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        LowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertDataChanged?.Invoke();
    }

    private void OnWarehouseChanged()
    {
        // When the warehouse changes, fetch new data immediately.
        _ = FetchAndNotifyAsync();
    }

    public async ValueTask DisposeAsync()
    {
        _warehouseState.OnChange -= OnWarehouseChanged;
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }
}

