@inject Services.WarehouseState WarehouseState
@implements IDisposable

<select class="form-select form-select-sm"
        style="max-width: 220px;"
        @onchange="OnWarehouseSelected"
        value="@WarehouseState.CurrentWarehouseId">
    @foreach (var wh in Services.WarehouseState.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnStateChanged;
    }

    private void OnWarehouseSelected(ChangeEventArgs e)
    {
        WarehouseState.SetWarehouse(e.Value?.ToString() ?? "");
    }

    private void OnStateChanged() => InvokeAsync(StateHasChanged);

    public void Dispose() => WarehouseState.OnChange -= OnStateChanged;
}

@inject Services.InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-2">@AlertService.LowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-2">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertDataChanged += _handler;
    }

    public void Dispose()
    {
        if (_handler is not null)
            AlertService.OnAlertDataChanged -= _handler;
    }
}

